import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import {
  Trash2,
  Download,
  Archive,
  Calendar,
  ShieldCheck,
  Eye,
  X,
  PieChart,
  FileText,
  Zap,
} from 'lucide-react';
import toast from 'react-hot-toast';

const formatDate = (dateStr) => {
  if (!dateStr) return '—';
  try {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-GB', {
      day: '2-digit',
      month: 'short',
      year: 'numeric',
    });
  } catch {
    return 'Invalid date';
  }
};

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  // ──────────────────────────────────────────────
  // Moved inside component → now allowed to use hooks
  // ──────────────────────────────────────────────
  const parseHoldings = useCallback((raw) => {
    if (!raw) return [];

    if (Array.isArray(raw)) {
      return raw.map((h) =>
        typeof h === 'string' ? h : h?.symbol || h?.ticker || String(h || '')
      );
    }

    let data = raw;

    if (typeof raw === 'string') {
      try {
        data = JSON.parse(raw);
      } catch {}
    }

    if (typeof data === 'string') {
      try {
        data = JSON.parse(data);
      } catch {}
    }

    if (Array.isArray(data)) {
      return data.map((h) =>
        typeof h === 'string' ? h : h?.symbol || h?.ticker || String(h || '')
      );
    }

    if (data && typeof data === 'object') {
      if (Array.isArray(data.holdings)) return parseHoldings(data.holdings);
      if (Array.isArray(data.assets)) return parseHoldings(data.assets);
      if (Array.isArray(data.positions)) return parseHoldings(data.positions);
    }

    return [];
  }, []); // ← empty deps = stable across renders

  const fetchHistory = useCallback(async () => {
    try {
      const { data } = await api.get('/portfolio/history');
      setHistory(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error('Failed to fetch portfolio history:', err);
      toast.error('Could not load your saved strategies');
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm('This strategy will be permanently deleted. Continue?')) return;

    const toastId = toast.loading('Deleting strategy...');
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory((prev) => prev.filter((item) => item.id !== id));
      toast.success('Strategy deleted', { id: toastId });
    } catch (err) {
      toast.error('Failed to delete strategy', { id: toastId });
    }
  };

  const handleDownload = async (item) => {
    const toastId = toast.loading('Generating PDF...');
    try {
      const { data } = await api.post('/portfolio/export', item, {
        responseType: 'blob',
      });

      const url = window.URL.createObjectURL(new Blob([data], { type: 'application/pdf' }));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_${item.id || 'export'}_${Date.now()}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);

      toast.success('PDF downloaded', { id: toastId });
    } catch (err) {
      toast.error('Failed to export PDF', { id: toastId });
    }
  };

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  if (loading) {
    return <div style={styles.center}>Synchronizing vault...</div>;
  }

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h2 style={styles.title}>
          <Archive size={20} color="var(--accent-primary)" /> Strategy Vault
        </h2>
        <span style={styles.badge}>
          {history.length} {history.length === 1 ? 'strategy' : 'strategies'}
        </span>
      </header>

      {history.length === 0 ? (
        <div style={styles.empty}>
          <p>No saved strategies yet.</p>
          <p style={{ fontSize: '0.9rem', marginTop: '0.5rem' }}>
            Generate and save your first investment strategy to see it here.
          </p>
        </div>
      ) : (
        <div style={styles.list}>
          {history.map((item) => (
            <div key={item.id} style={styles.card}>
              <div style={styles.cardContent}>
                <div style={styles.meta}>
                  <span style={styles.date}>
                    <Calendar size={12} /> {formatDate(item.created_at)}
                  </span>
                  <span style={styles.risk}>
                    <ShieldCheck size={12} /> Risk:{' '}
                    {item.risk_score != null ? Number(item.risk_score).toFixed(1) : '—'}
                  </span>
                </div>

                <h3 style={styles.goalTitle}>{item.goal || 'Unnamed Strategy'}</h3>

                <div style={styles.sectionBlock}>
                  <label style={styles.sectionLabel}>
                    <PieChart size={10} /> Holdings
                  </label>
                  <div style={styles.tickerGroup}>
                    {parseHoldings(item.holdings).length > 0 ? (
                      parseHoldings(item.holdings).map((ticker, i) => (
                        <span key={i} style={styles.ticker}>
                          {ticker}
                        </span>
                      ))
                    ) : (
                      <span style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}>
                        No holdings data
                      </span>
                    )}
                  </div>
                </div>
              </div>

              <div style={styles.actionColumn}>
                <button
                  onClick={() => setSelectedItem(item)}
                  style={styles.actionBtn}
                  title="View details"
                  aria-label="View strategy details"
                >
                  <Eye size={18} />
                </button>
                <button
                  onClick={() => handleDownload(item)}
                  style={styles.actionBtn}
                  title="Export as PDF"
                  aria-label="Download PDF report"
                >
                  <Download size={18} />
                </button>
                <button
                  onClick={() => handleDelete(item.id)}
                  style={styles.deleteBtn}
                  title="Delete permanently"
                  aria-label="Delete this strategy"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {selectedItem && (
        <div style={styles.overlay} onClick={() => setSelectedItem(null)}>
          <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
            <div style={styles.modalHeader}>
              <h4 style={styles.modalTitle}>
                Strategy Details — ID_{selectedItem.id || '?'}
              </h4>
              <button
                onClick={() => setSelectedItem(null)}
                style={styles.closeBtn}
                aria-label="Close modal"
              >
                <X size={20} />
              </button>
            </div>

            <div style={styles.modalBody}>
              <div style={styles.modalSection}>
                <h5 style={styles.modalLabel}>
                  <FileText size={14} /> Summary
                </h5>
                <p style={styles.modalText}>
                  {selectedItem.summary || 'No summary provided.'}
                </p>
              </div>

              <div style={styles.divider} />

              <div style={styles.modalSection}>
                <h5 style={styles.modalLabel}>
                  <Zap size={14} /> Rationale
                </h5>
                <div style={styles.rationaleBox}>
                  {selectedItem.rationale ? (
                    selectedItem.rationale.split('\n').map((line, i) => (
                      <p key={i} style={{ margin: '0.4em 0' }}>
                        {line}
                      </p>
                    ))
                  ) : (
                    <p style={{ color: 'var(--text-muted)' }}>No detailed rationale available.</p>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

